(3, 'Kerala', 'Munnar', 2800.0, 900.0, 600.0, 'https://images.unsplash.com/photo-1602216056096-3b40cc0c9944?w=600&q=80', '[{"day": 1, "title": "Tea Gardens", "desc": "Visit the Tata Tea Museum and wide stretches of tea plantations. Eravikulam National Park.", "image": "https://images.unsplash.com/photo-1595167732049-2eeb2be7e076?w=400&q=80"}, {"day": 2, "title": "Waterfalls & Dams", "desc": "Mattupetty Dam, Echo Point, and Attukal Waterfalls.", "image": "https://images.unsplash.com/photo-1593693397365-c3c1374582f3?w=400&q=80"}]'),
